+
+    async _semanticSearch(value, key, text, limit) {
+        const queryVec = await this._embedder.embed(text);
+        const scored = [];
+
+        // Batch encode items that aren't cached
+        const textsToEmbed = [];
+        const itemIndices = [];
+
+        for (let i = 0; i < value.length; i++) {
+            const item = value[i];
