+            for (let j = 0; j < itemVecs.length; j++) {
+                const idx = itemIndices[j];
+                const item = value[idx];
+                const itemText = textsToEmbed[j];
+                const itemVec = itemVecs[j];
+                const cacheKey = `${this.name}:${key}:${itemText}`;
