+                console.log('[WorkerStore] WebGPU not available');
+                return null;
+            }
+
+            const transformer = webgpu.getGPUTransformer();
+            const available = await transformer.init();
+
+            if (!available) {
+                console.log('[WorkerStore] WebGPU init failed');
+                return null;
+            }
