+        }
+
+        const schema = columns.map(col => ({
+            name: col.name,
+            type: DataType[(col.dataType || col.type)?.toUpperCase()] || col.dataType || col.type || 'string',
+            primaryKey: col.primaryKey || false,
+            vectorDim: col.vectorDim || null,
