+async function getStore(name, options = {}) {
+    const key = `${name}:${JSON.stringify(options)}`;
+    if (!stores.has(key)) {
+        const store = new WorkerStore(name, options);
+        await store.open();
+        stores.set(key, store);
+    }
+    return stores.get(key);
+}
