+export interface SearchStoreValue<T> {
+    query: string;
+    results: Array<{ item: T; score: number }>;
+    loading: boolean;
+    error: Error | null;
+}
+
+export interface CollectionStoreValue<T> {
+    items: T[];
+    loading: boolean;
+    error: Error | null;
+}
+
+export function createLanceStore<T = any>(
+    storeName: string,
+    key: string,
