+    async function set(value) {
+        try {
+            loading.value = true;
+            if (!store) store = await getStore(storeName, options.storeOptions);
+            await store.set(key, value);
+            data.value = value;
+            loading.value = false;
+        } catch (e) {
+            error.value = e;
+            loading.value = false;
+        }
+    }
+
+    async function remove() {
+        try {
+            if (!store) store = await getStore(storeName, options.storeOptions);
+            await store.delete(key);
+            data.value = undefined;
+        } catch (e) {
