+        maxScore = max(maxScore, score);
+    }
+
+    // Softmax: exp(score - max) / sum(exp(scores - max))
+    var sumExp: f32 = 0.0;
+    for (var keyPos: u32 = 0u; keyPos < params.seqLen; keyPos = keyPos + 1u) {
+        scores[keyPos] = exp(scores[keyPos] - maxScore);
+        sumExp = sumExp + scores[keyPos];
+    }
+
+    for (var keyPos: u32 = 0u; keyPos < params.seqLen; keyPos = keyPos + 1u) {
