+    let tokenIdx = idx / params.embeddingDim;
+    let dimIdx = idx % params.embeddingDim;
+
+    // Get token ID
+    let tokenId = tokenIds[tokenIdx];
+
+    // Bounds check
+    if (tokenId >= params.vocabSize) {
+        output[idx] = 0.0;
+        return;
+    }
+
+    // Look up embedding
+    output[idx] = embeddings[tokenId * params.embeddingDim + dimIdx];
