+    let idx = global_id.x;
+    if (idx >= params.size) {
+        return;
+    }
+
+    let x = inplace[idx];
+    let sigmoid = 1.0 / (1.0 + exp(-1.702 * x));
+    inplace[idx] = x * sigmoid;
