+            }
+
+            return Array.isArray(parsed) ? parsed : [parsed];
+        } catch (e) {
+            console.warn('[WorkerDatabase] Failed to parse fragment:', e);
+            return [];
+        }
+    }
+
+    _parseJsonColumnar(data) {
+        const { schema, columns, rowCount } = data;
+        const rows = [];
