+    }
+
+    async compact() {
+        for (const [tableName, table] of this.tables) {
+            const allRows = await this._readAllRows(tableName);
+
+            for (const fragKey of table.fragments) {
+                await opfsStorage.delete(fragKey);
+            }
+
+            table.fragments = [];
+            table.deletionVector = [];
+            table.rowCount = 0;
+            table.nextRowId = 0;
+
+            if (allRows.length > 0) {
