+    let x3 = x * x * x;
+    let inner = SQRT_2_OVER_PI * (x + 0.044715 * x3);
+
+    // tanh approximation: (exp(2x) - 1) / (exp(2x) + 1)
+    let exp2x = exp(2.0 * inner);
+    let tanh_val = (exp2x - 1.0) / (exp2x + 1.0);
